#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, A, B;
        scanf("%d %d %d", &N, &A, &B);
        int t[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &t[i]);
        }
        int count = 0;
        int last_haircut = 0;
        for (int i = 0; i < N; i++) {
            if (t[i] - last_haircut >= A && t[i] - last_haircut <= B) {
                count++;
            } else {
                last_haircut = t[i];
                count = 1;
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

