import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int A = sc.nextInt();
            int B = sc.nextInt();
            int[] t = new int[N];
            for (int i = 0; i < N; i++) {
                t[i] = sc.nextInt();
            }
            int count = 0;
            int last_haircut = 0;
            for (int i = 0; i < N; i++) {
                if (t[i] - last_haircut >= A && t[i] - last_haircut <= B) {
                    count++;
                } else {
                    last_haircut = t[i];
                    count = 1;
                }
            }
            System.out.println(count);
        }
    }
}

